    for (int i = 1; i < top; i++) { //凸包中的所有点
        Vector tmp = vec[stk[i + 1]] - vec[stk[i]];
        res += sqrt(pow(tmp.x, 2) + pow(tmp.y , 2));
    }   
    return res;
}

int main() {
    std::ios::sync_with_stdio(false), cin.tie(0), cout.tie(0);
    int n;
    double a, b, r;
    cin >> n >> a >> b >> r;
    a = a / 2 - r, b = b / 2 - r;
    for (int i = 1; i <= n; i++) {
        double x, y, theta;
        cin >> x >> y >> theta;
        double len = sqrt(pow(a, 2) + pow(b, 2));
        double alpha1 = atan2(a, b) + theta;
        double alpha2 = atan2(a, -b) + theta;
        double alpha3 = atan2(-a, -b) + theta;
        double alpha4 = atan2(-a, b) + theta;
        vec[++cnt] = Vector(x + len * cos(alpha1), y + len * sin(alpha1));
        vec[++cnt] = Vector(x + len * cos(alpha2), y + len * sin(alpha2));
        vec[++cnt] = Vector(x + len * cos(alpha3), y + len * sin(alpha3));
        vec[++cnt] = Vector(x + len * cos(alpha4), y + len * sin(alpha4));
    }
    cout << setprecision(2) << fixed << convex() + acos(-1) * r * 2.0 << endl;
    return 0;
}
```

## F CERC2016 凸轮廓线 Convex Contour
### Problem
[题目链接](https://www.luogu.com.cn/problem/P3680)
### Solution
将正方形和矩形的顶点计入，圆不能仅将上下两个点计入求凸包。
对于圆，可割圆法变为正1e4边形，将顶点计入求凸包。
### Code
```cpp Convex Contour
#include <bits/stdc++.h>
#define PI acos(-1)

using namespace std;

constexpr int MAXN = 2e5 + 5;
constexpr int M = 1e4;

struct Vector {
    double x = .0, y = .0;

    Vector() = default;
    Vector(double _x, double _y) : x(_x), y(_y) {}

    friend inline bool operator<(const Vector& a, const Vector& b) {
        return a.x == b.x ? a.y < b.y : a.x < b.x;
    }

    friend inline Vector operator-(const Vector& a, const Vector& b) {
        return Vector(a.x - b.x, a.y - b.y);
    }

    friend inline double operator*(const Vector& a, const Vector& b) {
        return a.x * b.y - a.y * b.x;  //×
    }
} vec[MAXN];

int cnt;
int stk[MAXN], used[MAXN], top(0);

inline double convex(double res) {
    sort(vec + 1, vec + cnt + 1);
    stk[++top] = 1;
    for (int i = 2; i <= cnt; i++) { //下凸壳
        while (top > 1 &&
               (vec[stk[top]] - vec[stk[top - 1]]) * (vec[i] - vec[stk[top]]) <= 0)
            used[stk[top--]] = false;
        used[i] = true;
        stk[++top] = i;
    }
    int tmp = top;
    for (int i = cnt - 1; i > 0; i--) { //上凸壳
        if (!used[i]) {
            while (top > tmp && (vec[stk[top]] - vec[stk[top - 1]]) *
                                        (vec[i] - vec[stk[top]]) <= 0)
                used[stk[top--]] = false;
            used[i] = true;
            stk[++top] = i;
        }
    }
    for (int i = 1; i < top; i++) { //凸包中的所有点
        Vector tmp = vec[stk[i + 1]] - vec[stk[i]];
        res += sqrt(pow(tmp.x, 2) + pow(tmp.y , 2));
    }   
    return res;
}

int main() {
    std::ios::sync_with_stdio(false), cin.tie(0), cout.tie(0);
    double n, st(0);
    string s;
    cin >> n >> s;
    for (int i = 0; i < s.size(); i++) {
        if (s[i] == 'S') {
            vec[++cnt] = Vector(st, 0);
            vec[++cnt] = Vector(st, 2);
            vec[++cnt] = Vector(st + 2, 0);
            vec[++cnt] = Vector(st + 2, 2);
        } else if (s[i] == 'T') {
            vec[++cnt] = Vector(st, 0);
            vec[++cnt] = Vector(st + 2, 0);
            vec[++cnt] = Vector(st + 1, sqrt(3.0));
        } else {
            for (int j = 1; j <= M; j++) {
                double theta = PI * 2 * j / M;
                vec[++cnt] = Vector(st + 1 + cos(theta), 1 + sin(theta));
            }
        }
        st += 2;
    }
    cout << setprecision(14) << fixed << convex(0) / 2 << endl;
    return 0;
}
```

# 小Z的袜子
  - [题目链接](https://www.luogu.com.cn/problem/P1494)
  - 分块/莫队

<!-- more -->
# Description
多组询问求给定区间 $[l_i,r_i]$ 中取出相同两个数的概率。
# Solution
  - 设区间内某种颜色的数目为 $cnt_{color}$。
  - 则概率为 $\frac{\Sigma{}cnt_{color}(cnt_{color} − 1)}{(r − l + 1)(r − l)}$。
  - 将询问分块，一般取块的长度为 $sqrt(n)$ 或 $\frac{n}{sqrt(2 * m / 3)}$。询问所在的块由询问左端点$l_i$ 决定。
    ```cpp
    read(n), read(m), Len = n / sqrt(m * 2.0 / 3);
    for (int i = 1; i <= n; i++) cin >> c[i];
    for (int i = 1; i <= m; i++) 
        read(Q[i].l), read(Q[i].r), Q[i].id = i, Q[i].block = Q[i].l / Len;
    sort(Q + 1, Q + m + 1, cmp1);
    ```
  - 排序: 询问 $q_i$，$q_j$所在块相同则按其右端点排序，否则按块的编号升序排序。
    ```cpp
    struct query {
        int l, r, id, block, x/*记录询问分子*/, y/*记录询问分母*/;
    }Q[MAXN];

    inline bool cmp1 (const query &a, const query &b) {
      return (a.block== b.block) ? a.r < b.r : a.block < b.block;
    }
    inline bool cmp2 (const query &a, const query &b) { //按照原始顺序排序
        return a.id < b.id;
    }
    ```
  - 询问时，用 $l$，$r$ 记录上一次询问的位置(初始均为 1)，不断加减扩展即可(求的是 $\Delta$)。

# Code
```cpp 小Z的袜子
#include<bits/stdc++.h>
#define int long long

constexpr int MAXN = 5e4 + 4;

using namespace std;

template <typename T> inline void read(T &x) {
    int f = 1; x = 0; 
    char ch = getchar();
    while (!isdigit(ch)) f = (ch == '-') ? -1 : 1, ch = getchar();
    while (isdigit(ch)) x = x * 10 + ch - 48, ch = getchar();
    x *= f;
}

int n, m, Len, l, r, ans;
int c[MAXN], cnt[MAXN];
struct query {
    int l, r, id, block, x/*记录询问分子*/, y/*记录询问分母*/;
}Q[MAXN];

inline bool cmp1 (const query &a, const query &b) {
    return (a.block== b.block) ? a.r < b.r : a.block < b.block;
}

inline bool cmp2 (const query &a, const query &b) { //按照原始顺序排序
    return a.id < b.id;
}

inline int gcd(int x, int y) {
    return !y ? x : gcd(y, x % y);
}

signed main(){
    read(n), read(m), Len = n / sqrt(m * 2.0 / 3);
    for (int i = 1; i <= n; i++) read(c[i]);
    for (int i = 1; i <= m; i++) 
        read(Q[i].l), read(Q[i].r), Q[i].id = i, Q[i].block = Q[i].l / Len;
    sort(Q + 1, Q + m + 1, cmp1);
    l = 1, r = 0;
    for (int i = 1; i <= m; i++) {
        while (r < Q[i].r) {
            r++;
            ans -= cnt[c[r]] * (cnt[c[r]] - 1);
            cnt[c[r]]++;
            ans += cnt[c[r]] * (cnt[c[r]] - 1);
        }
        while (r > Q[i].r) {
            ans -= cnt[c[r]] * (cnt[c[r]] - 1);
            cnt[c[r]]--;
            ans += cnt[c[r]] * (cnt[c[r]] - 1);
            r--;
        }
        while (l < Q[i].l) {
            ans -= cnt[c[l]] * (cnt[c[l]] - 1);
            cnt[c[l]]--;
            ans += cnt[c[l]] * (cnt[c[l]] - 1);
            l++;
        }
        while (l > Q[i].l) {
            l--;
            ans -= cnt[c[l]] * (cnt[c[l]] - 1);
            cnt[c[l]]++;
            ans += cnt[c[l]] * (cnt[c[l]] - 1);
        }
        Q[i].x = ans, Q[i].y = (Q[i].r - Q[i].l + 1) * (Q[i].r - Q[i].l);
    }
    sort(Q + 1, Q + m + 1, cmp2);
    for (int i = 1; i <= m; i++)
        if (Q[i].l == Q[i].r) puts("0/1");
        else printf("%lld/%lld\n", Q[i].x / gcd(Q[i].x, Q[i].y), Q[i].y / gcd(Q[i].x, Q[i].y));
    return 0;
}
```

# Best Cow Line G
  - [题目链接](https://www.luogu.com.cn/problem/P2870)
  - Hash/字符串Hash
  - 二分答案
  - 倍增

<!-- more -->
# Description
给定长度为 $N$ 的字符串 $S$，每次可从 $S$ 的两端选取一个字符插入空字符串 $T$ 尾部。求字典序最小的字符串 $T$。
# Solution
考虑贪心：比较当前 $S$ 与 $reverse(S)$ 的字典序，如果 $S$ 的字典序小则从 $S$ 头部取出字符；否则从尾部取出。
本题数据加强，逐位比较会被卡。需 $hash$ + 二分或倍增求出最长相同前缀子串，比较下一个位置的大小。
注：字符串 $hash$(%) 不能直接用来比较字符串大小。
# Code
## 二分子串长度
```cpp Best Cow Line G
#include<bits/stdc++.h>

typedef unsigned long long uLL;
constexpr int MAXN = 5e5 + 5;
constexpr uLL base = 13331;

using namespace std;

int n;
uLL H1[MAXN], H2[MAXN], P[MAXN] = {1};
char s[MAXN], revs[MAXN];
string ans;

inline void Init() {
    for (int i = 1; i <= n; i++) P[i] = P[i - 1] * base;
    for (int i = 1; i <= n; i++) H1[i] = H1[i - 1] * base + s[i] - 'A' + 1;
    for (int i = 1; i <= n; i++) H2[i] = H2[i - 1] * base + revs[i] - 'A' + 1;
}

inline uLL getHash(int l, int r, uLL * H) {
    return H[r] - H[l - 1] * P[r - l + 1];
}

inline bool compare(int l, int r) {
    int L = 0, R = r - l, len = -1;
    while (L <= R) {
        int mid = (L + R) >> 1;
        if (getHash(l, l + mid, H1) == getHash(n - r + 1, n - r + 1 + mid, H2)) 
            len = mid, L = mid + 1;
        else R = mid - 1;
    }
    return s[l + len + 1] < s[r - len - 1];
}

int main(){
    cin >> n;
    for (int i = 1; i <= n; i++) 
        getchar(), s[i] = getchar(), revs[n - i + 1] = s[i];
    Init();
    int l = 1, r = n;
    while (l <= r) {
        if (compare(l, r)) ans += s[l], l++;
        else ans += s[r], r--;
    }
    for (int i = 0; i < n; i++) {
        if (i && i % 80 == 0) putchar('\n');
        putchar(ans[i]);
    }
    return 0;
}
```
## 倍增
```cpp Best Cow Line G
#include <bits/stdc++.h>


typedef unsigned long long uLL;
constexpr uLL base = 13331;
constexpr int MAXN = 5e5 + 5;

using namespace std;

int n;
uLL H1[MAXN], H2[MAXN], P[MAXN] = {1};
char s[MAXN], revs[MAXN];
string ans;

inline void Init() {
    for (int i = 1; i <= n; i++) P[i] = P[i - 1] * base;
    for (int i = 1; i <= n; i++) H1[i] = H1[i - 1] * base + s[i] - 'A' + 1;
    for (int i = 1; i <= n; i++) H2[i] = H2[i - 1] * base + revs[i] - 'A' + 1;
}

inline uLL getHash(int l, int r, uLL* H) {
    return H[r] - H[l - 1] * P[r - l + 1];
}

inline bool compare(int l, int r) {
    int len = 1, Lst = l - 1, Rst = n - r;
    while (len) {
        if (Lst + len <= r &&
            getHash(l, Lst + len, H1) == getHash(n - r + 1, Rst + len, H2)) {
            Lst += len, Rst += len, len <<= 1;
        } else
            len >>= 1;
    }
    return s[Lst + 1] < revs[Rst + 1];
}

int main() {
