    for (int i = 1; i <= n; i++)
        getchar(), s[i] = getchar(), revs[n - i + 1] = s[i];
    Init();
    int l = 1, r = n;
    while (l <= r) {
        if (compare(l, r)) ans += s[l], l++;
        else ans += s[r], r--;
    }
    for (int i = 0; i < n; i++) {
        if (i && i % 80 == 0) putchar('\n');
        putchar(ans[i]);
    }
    return 0;
}
